#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vUv = fract(vUv);
vec2 dither_uv = vUvOriginal*uTexSize.xy*texsize_noise_lq.zw * 1 + rand_frame.xy;
vec2 d = uTexSize.zw*12;
vec3 dx = GetBlur3(vUvOriginal + vec2(1,0)*d) - GetBlur3(vUvOriginal -vec2(1,0)*d);
vec3 dy = GetBlur3(vUvOriginal + vec2(0,1)*d) - GetBlur3(vUvOriginal -vec2(0,1)*d);

vec2 uvx = vUv
           + (texture(sampler_noise_lq, dither_uv).xy-0.5)*uTexSize.zw*0
           - vec2(dx.x,dy.x)*uTexSize.zw*8;
    ret.x = texture( sampler_fc_main, uvx ).x
          - (GetBlur3(uvx)-texture( sampler_fc_main, uvx )).x*0.1
          - 0.03;

vec2 uvy = vUv
           + (texture(sampler_noise_lq, dither_uv).xy-0.5)*uTexSize.zw*4
           - vec2(dx.x,dy.x)*uTexSize.zw*4
           + vec2(dx.y,dy.y)*uTexSize.zw*8;

ret.y = tex2d(sampler_fc_main,uvy).y
      + (texture(sampler_noise_lq, dither_uv).xyz-0.5)*0.1
      - 0.012
      + (tex2d(sampler_pc_main,vUv).z)*0.2;


vec2 uvz = mix(vUvOriginal,vUv,0.04)
           + (texture(sampler_noise_lq, dither_uv).xy-0.5)*uTexSize.zw*0
           + vec2(dy.x,-dx.x)*uTexSize.zw*64
           + vec2(dx.z,dy.z)*uTexSize.zw*0;
ret.z = tex2d(sampler_fc_main,uvz).z
      + (tex2d(sampler_fc_main,uvz).z-GetBlur2(uvz).z)*0.3
      + (texture(sampler_noise_lq, dither_uv).xyz)*0.12
      - GetBlur3(vUvOriginal).x
      - clamp01(1-GetBlur3(vUvOriginal).x)*0.04;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;



float z = q30;
float d = q31;
float pi = q28;
float pi2inv = q29;
float mask_apex = q32;
float zoom = q27;

vec2 c = zoom*(vUv-0.5)*uAspect.xy;

float camera_apex = atan( length(c),z);

bool mask = mask_apex >= camera_apex;

float longitude = atan(c.x,c.y);
float latitude = (pi - camera_apex + asin(d*sin(camera_apex)));

vec2 polar = vec2(longitude,latitude);

vec3 p = vec3( sin(polar.x)*sin(polar.y),cos(polar.x)*sin(polar.y),cos(polar.y));

factorA = p.zy;
factorB = vec2(q20,q21);
product = vec2( factorA.x*factorB.x - factorA.y*factorB.y,factorA.x*factorB.y + factorA.y*factorB.x);
p.zy = product.xy;

factorA = p.zx;
factorB = vec2(q22,q23);
product = vec2( factorA.x*factorB.x - factorA.y*factorB.y,factorA.x*factorB.y + factorA.y*factorB.x);
p.zx = product.xy;

factorA = p.yx;
factorB = vec2(q24,q25);
product = vec2( factorA.x*factorB.x - factorA.y*factorB.y, factorA.x*factorB.y + factorA.y*factorB.x);
p.yx = product.xy;

polar = vec2(atan(p.z,p.x),atan(p.y,length(p.xz)))*pi2inv*vec2(1,2)+vec2(0,0.5);

//Eo.S's mirror code!
vec2 polar2 = 1.0 - abs( fract( polar  ) * 2.0 - 1.0 );

vec2 uv1 = vec2(polar2.x-q6, polar2.y-q5);

vec2 hor = vec2 (uTexSize.z*1,0);
vec2 ver = vec2 (0,uTexSize.w*1);
float dx = GetPixel (polar2-hor) - GetPixel (polar2+hor);
float dy = GetPixel (polar2-ver) - GetPixel (polar2+ver);
vec2 dz = vec2 (dx,dy);

uv1 = uv1*0+.3*cos(uv1*2) - dz;
float dots = clamp01(.04/length(uv1));
uv1 = uv1*0+.3*cos(uv1*12) - 9*dz;
vec3 dots2 = clamp01(.04/length(uv1));
dots -= lum(GetBlur2(polar2));

ret = dots + GetPixel(polar2)*12*dots2;

//ret = texture(sampler_main,polar2);

//ret = mix(ret,1,mask*tex2d(sampler_pano_earth_clouds,polar)*audioMidSmooth*0.5);


c = -(vUv-0.5)*uAspect.xy;
polar = vec2( atan(c.x,z), atan(c.y,z));
p = vec3( sin(polar.x)*cos(polar.y),sin(polar.y)*cos(polar.x),cos(polar.x)*cos(polar.y));
factorA = p.zy;factorB = vec2(q20,q21);
product = vec2( factorA.x*factorB.x - factorA.y*factorB.y,factorA.x*factorB.y + factorA.y*factorB.x);
p.zy = product.xy;factorA = p.zx;factorB = vec2(q22,q23);
product = vec2( factorA.x*factorB.x - factorA.y*factorB.y,factorA.x*factorB.y + factorA.y*factorB.x);
p.zx = product.xy;factorA = p.yx;factorB = vec2(q24,q25);
product = vec2( factorA.x*factorB.x - factorA.y*factorB.y, factorA.x*factorB.y + factorA.y*factorB.x);
p.yx = product.xy;polar = vec2( atan(p.x,p.z),atan(p.y,length(p.xz))*2)*pi2inv + vec2(0,0.5);

polar2 = 1.0 - abs( fract( polar  ) * 2.0 - 1.0 );

uv1 = vec2(polar2.x-q6, polar2.y-q5);

hor = vec2 (uTexSize.z,0);
ver = vec2 (0,uTexSize.w*1);
dx = GetPixel (polar2-hor) - GetPixel (polar2+hor);
dy = GetPixel (polar2-ver) - GetPixel (polar2+ver);
dz = vec2 (dx,dy);

uv1 = uv1*0+.3*cos(uv1*2) - dz;
dots = clamp01(.04/length(uv1));
uv1 = uv1*0+.3*cos(uv1*12) - 9*dz;
dots2 = clamp01(.04/length(uv1));
dots -= lum(GetBlur2(polar2));

ret = mix(ret,pow(dots + GetPixel(polar2)*12*dots2,1.75).yzx,(1-mask));


  fragColor = ret;
}
